"use strict";(globalThis.webpackChunkcf_infra_docs=globalThis.webpackChunkcf_infra_docs||[]).push([[28351],{78917(e){e.exports=JSON.parse('{"tag":{"label":"advanced","permalink":"/docs/tags/advanced","allTagsPath":"/docs/tags","count":13,"items":[{"id":"how-to/advanced","title":"Advanced","description":"The following how-to guides are available in this category:","permalink":"/docs/how-to/advanced"},{"id":"how-to/advanced/numpy","title":"Building Against NumPy","description":"Finding numpy.get_include() in setup.py, numpy in build-system.requires of pyproject.toml, dependency(\'numpy\') in meson.build, or cimport statements in .pyx or .pyd files are a telltale sign that the package links against NumPy.","permalink":"/docs/how-to/advanced/numpy"},{"id":"how-to/advanced/windows","title":"Building packages for Windows","description":"The following guides cover topics specific to building packages for Windows on conda-forge.","permalink":"/docs/how-to/advanced/windows"},{"id":"how-to/advanced/windows/cmd-batch-syntax","title":"CMD/Batch scripting for Windows recipes","description":"Windows recipes rely on CMD/Batch scripts (.bat) by default.","permalink":"/docs/how-to/advanced/windows/cmd-batch-syntax"},{"id":"how-to/advanced/windows/notes-on-native-code","title":"Compiling native code on Windows with MSVC","description":"In order to compile native code (C, C++, etc.) on Windows, you will need to","permalink":"/docs/how-to/advanced/windows/notes-on-native-code"},{"id":"how-to/advanced/self-hosted-runners","title":"How to configure self-hosted runners","description":"conda-forge has access to additional CI resources for feedstocks that can\'t build their packages in the default runners. Check Reference> Runners for a comprehensive list.","permalink":"/docs/how-to/advanced/self-hosted-runners"},{"id":"how-to/advanced/enable-archs","title":"How to enable additional architectures","description":"By default, feedstocks are created with support for the main platforms (e.g. linux-64, osx-64, win-64). Additional ones may be available in an opt-in fashion. The configuration can be changed manually in conda-forge.yml, or through automated migrations.","permalink":"/docs/how-to/advanced/enable-archs"},{"id":"how-to/advanced/several-versions","title":"How to maintain several versions","description":"The conda-forge workflow assumes that a push to any branch in the feedstock repository will result in a build being uploaded to the conda-forge channel (and that\'s why PRs must always be opened from a fork!).","permalink":"/docs/how-to/advanced/several-versions"},{"id":"how-to/advanced/package-a-fork","title":"How to package a fork","description":"Sometimes you face the possibility of needing to package a fork.","permalink":"/docs/how-to/advanced/package-a-fork"},{"id":"how-to/advanced/talk-to-the-bots","title":"How to talk to the bots","description":"Some parts of the conda-forge automation are exposed as \\"bot commands\\" that can be invoked from issue titles and comments. You can check the full list in the admin-web-services documentation.","permalink":"/docs/how-to/advanced/talk-to-the-bots"},{"id":"how-to/advanced/autotools-to-cmake","title":"Moving from an autotools build to a CMake build","description":"Some packages maintain both an Autotools build and a CMake build. Some maintainers","permalink":"/docs/how-to/advanced/autotools-to-cmake"},{"id":"how-to/advanced/run-package-tests-off-ci","title":"Run package tests off CI","description":"Despite having a successful build, sometimes we can\'t run all the tests we\'d like on CI. Some reasons include:","permalink":"/docs/how-to/advanced/run-package-tests-off-ci"},{"id":"how-to/advanced/windows/local-testing","title":"Testing and debugging Windows builds locally","description":"The first thing that you should know is that you can locally test Windows","permalink":"/docs/how-to/advanced/windows/local-testing"}],"unlisted":false}}')}}]);